onReady(setupModals);const DIRECTION_HORIZONTAL=Symbol();const DIRECTION_VERTICAL=Symbol();const INTENT_BEFORE=Symbol();const INTENT_AFTER=Symbol();const EVENTYAY_CSRF_TOKEN=document.cookie.split('eventyay_csrftoken=').pop().split(';').shift()
